        converted_counts = {}
        for bitstring, count in counts.items():
            converted_counts[bitstring[::-1]] = count
        expectation = compute_expectation(converted_counts, graph)
        return -expectation

    initial_params = [0.1] * circuit.num_parameters
    result = minimize(objective, initial_params, method='COBYLA', options={'maxiter': 100})

    optimal_theta = result.x[0]
    optimal_gamma = result.x[1]
    parameter_binds = [{circuit.parameters[0]: [optimal_theta], circuit.parameters[1]: [optimal_gamma]}]
    transpiled_circuit = transpile(circuit, aer_sim)
    job = aer_sim.run(transpiled_circuit, parameter_binds=parameter_binds, shots=4096)
    final_result = job.result()
    final_counts = final_result.get_counts()

