        converted_counts[bitstring[::-1]] = count

    sorted_counts = sorted(converted_counts.items(), key=lambda x: x[1], reverse=True)

    top_two = []
    for i in range(min(2, len(sorted_counts))):
        top_two.append(sorted_counts[i][0])

    return top_two
"""
